    readonly actions: Readonly<Record<string, Action>>;

    /** Регистрация динамических свойств. */
    readonly dynamics: Readonly<Record<string, Dynamic>>;

    /** Регистрация представлений. */
    readonly views: Readonly<Record<string, View>>;

    /** Регистрация контейнеров представлений. */
    readonly viewsContainers: Readonly<Record<string, ViewsContainer>>;

    /** Массив меню. */
    readonly menu: readonly MenuAction[];

