/**
 * Интерфейс контекста чертежа.
 */
declare interface CadViewContext {
    /** Текущий составной слой. */
    readonly layer: CadViewCompoundLayer;

    /** Соотношение пикселей устройства. */
    readonly devicePixelRatio: number;

    /** Слоя аннотаций. */
    readonly annotations: AnnotationLayers;

    /** Камера. */
    readonly camera: Camera;

    /** Возможность переключения камеры. */
    readonly allowCameraSwitch: boolean;

    /**
     * Ближайший объект в точке.
     * @param px Координаты точки.
     * @param predicate Предикат фильтра (опционально).
     */
    nearestObjectAt(px: vec2, predicate?: ObjectPredicate): SearchObjectResult | undefined;

    /**
     * Объекты в указанной точке.
     * @param px Координаты точки.
     * @param predicate Предикат фильтра (опционально).
     */
    objectsAt(px: vec2, predicate?: ObjectPredicate): Generator<SearchObjectResult>;

    /**
     * Принять введённое значение.
     * @param value Любое значение.
     */
    accept(value: unknown): void;

    /**
     * Отменить операцию.
     */
    cancel(): void;

    /**
     * Остановить анимацию.
     */
    pauseAnimation(): void;

    /**
     * Проверить занятость.
     */
    busy(): boolean;

    /**
     * Получить координаты точки.
     * @param message Сообщение для подсказки.
     * @param alts Альтернативные команды (опционально).
     * @param p Точка или луч (опционально).
     * @param handler Callback-обработчик (опционально).
     */
    getpoint(message: string, alts?: AlternativeCommands, p?: vec3 | ray3, handler?: DynamicPaint): Promise<vec3 | string>;

    /**
     * Получить объект.
     * @param message Сообщение для подсказки.
     * @param alts Альтернативные команды (опционально).
     * @param predicate Предикат фильтра (опционально).
     * @param handler Callback-обработчик (опционально).
     */
    getobject(message: string, alts?: AlternativeCommands, predicate?: ObjectPredicate, handler?: DynamicPaint): Promise<CadViewObject | string>;

    /**
     * Пересчитать экран.
     * @param keep Признак сохранения результатов (опционально).
     */
    invalidate(keep?: boolean): void;

    /**
     * Расширить зону рендера.
     */
    extends(): void;

    /**
     * Перерисовать экран.
     */
    repaint(): void;

    /**
     * Устанавливает матрицу представления, чтобы камера "смотрела" в определённом направлении.
     *
     * @param position - Позиция камеры в трёхмерном пространстве.
     * @param direction - Направление, в котором смотрит камера.
     * @param up - Вектор, указывающий "вверх" для камеры (по умолчанию используется стандартный).
     * @param animate - Анимировать ли перемещение камеры.
     * @param pivot - Поменять опорную точку камеры.
     */
    lookAt(position: vec3, direction: vec3, up?: vec3, animate?: boolean, pivot?: vec3): void;

    /**
     * Проиграть анимацию.
     *
     * @param duration - Длительность анимации в секундах.
     * @param frame - Вызываемая функция.
     * @param handler - Метод динамического рисования
     */
    animate(duration: number, frame?: AnimateRequestCallback, handler?: DynamicPaint): Promise<bool>;
    
    /**
     * Сохраняет текущее состояние вида.
     *
     * @returns Данные, представляющие сохранённое состояние вида.
     */
    storeView(): any;

    /**
     * Восстанавливает состояние вида из ранее сохранённых данных.
     *
     * @param data Данные, полученные из функции `storeView()
     */
    restoreView(data: any);

    /**
     * Устанавливает тип камеры, используемой для отображения сцены.
     *
     * @param type - Тип камеры, который необходимо установить.
     */
    setCameraType(type: CameraType): void;

    /** Настройки чертежа. */
    readonly settings: CadViewSettings;
}

/**
 * Интерфейс настроек чертежа.
 */
declare interface CadViewSettings {
    /** Режим привязок. */
    osMode: ObjectSnapMode;

    /** Тип захвата точек. */
    snapType: SnapType;

    /** Автоматический захват. */
    autoSnap: Autosnap;

    /** Режим полярного угла. */
    polarMode: PolarMode;

    /** Отображение траекторий движения. */
    trackPath: TrackPath;

    /** Пара сплайнов. */
    snapPair: SnapPair;

    /** Размер апертуры. */
    aperture: number;

    /** Флажок ограничения зоны выбора. */
    apertureBox: boolean;

    /** Базовый угол вращения. */
    angleBase: number;

    /** Направление углов. */
    angleDir: boolean;

    /** Расстояние полярного перемещения. */
    polarDistance: number;

    /** Угол полярного шага. */
    polarAngle: number;

    /** Цвет треков. */
    trackColor: number;

    /** Размер шагов захвата. */
    snapSize: number;

    /** Высота перспективы. */
    elevation: number;

    /** Начало системы координат UCS. */
    ucsOrigin: vec3;

    /** Ось X системы координат UCS. */
    ucsX: vec3;

    /** Ось Y системы координат UCS. */
    ucsY: vec3;

    /** Признак включения изометричного захвата. */
    isometricSnapEnabled: boolean;

    /** Угол изометричной плоскости. */
    snapAngle: number;

    /** Признак активированного автоматического захвата. */
    snapEnabled: boolean;

    /** Размеры единиц измерения. */
    snapUnits: vec2;

    /** Основание сетки. */
    gridBase: vec2;

    /** Использование динамического ввода. */
    dynInput: boolean;

    /**
    * Представляет значение масштабирования по оси Z.
    */
    scaleRatio?: number;
}

/**
 * Тип массива индексов вершин.
 */
declare type GeometryIndices = Uint8Array | Uint16Array | Uint32Array;

/**
 * Интерфейс геометрической фигуры.
 */
declare interface Geometry3d {
    /** Массив вершин. */
    vertices: Float32Array;

    /** Массив нормалей. */
    normals: Float32Array;

    /** Массив UV (текстурные координаты, необязательно). */
    uv?: Float32Array;

    /** Массив цветов (необязательно). */
    colors?: Uint32Array;

    /** Индексы вершин. */
    indices: GeometryIndices;
}

/**
 * Интерфейс уникальной геометрии с UUID.
 */
declare interface UuidGeometry3d extends Readonly<Geometry3d> {
    /** Уникальный идентификатор геометрии. */
    readonly uuid: string;

    /** Ограничивающий прямоугольник. */
    readonly bounds: box3;
}

/**
 * RGB-значение цвета (нормализованный uint8).
 */
type rgb8unorm = number;

/**
 * RGBA-значение цвета (нормализованный uint8).
 */
type rgba8unorm = number;

/**
 * Интерфейс материала Blinn-Phong.
 */
declare interface BlinnPhongMaterial {
    /** Тип затенения. */
    shading: 'Blinn–Phong';

    /** Диффузный цвет. */
    diffuse: rgb8unorm;

    /** Зеркальный отражённый цвет. */
    specular: rgb8unorm;

    /** Амбиентный цвет. */
    ambient: rgb8unorm;

    /** Степень блеска поверхности. */
    shininess: number;

    /** Коэффициент прозрачности. */
    transparency: number;
}

/**
 * Интерфейс материала рельефа местности.
 */
declare interface TerrainMaterial {
    /** Тип затенения. */
    shading: 'Terrain';

    /** Карта диффузного освещения. */
    diffuseMap: string;

    /** Карта высот. */
    bumpMap: string;

    /** Повтор карты диффузного освещения. */
    diffuseRepeat: number;

    /** Масштаб высоты. */
    heightScale: number;

    /** Порог. */
    threshold: number;

    /** Мощность зеркальной составляющей. */
    specularPower: number;

    /** Уровень зеркальной составляющей. */
    specularLevel: number;
}

/**
 * Универсальный материал с UUID.
 */
declare type UuidMaterial = Readonly<Material> & {
    readonly uuid: string;
};

/**
 * Материалы в целом.
 */
declare type Material = BlinnPhongMaterial | TerrainMaterial;

/**
 * Интерфейс графического контекста устройства.
 */
declare interface DeviceContext {
    /**
     * Сбросить контекст устройства.
     */
    reset(): void;

    /**
     * Начертить линию.
     * @param p Первая точка линии.
     */
    newpath(p?: vec2): void;

    /**
     * Нарисовать отрезок прямой.
     * @param p Вторая точка линии.
     */
    lineto(p: vec2): void;

    /**
     * Нарисовать дугу окружности.
     * @param center Центр окружности.
     * @param radius Радиус окружности.
     * @param angle Угол начала дуги.
     * @param span Угловой размер дуги.
     */
    arcto(center: vec2, radius: number, angle: number, span: number): void;

    /**
     * Заливка замкнутых контуров.
     * @param width Толщина границы (необязательно).
     * @param closed Замкнутость фигуры (необязательно).
     */
    stroke(width?: number, closed?: boolean): void;

    /**
     * Заливка внутренних областей.
     */
    fill(): void;

    /**
     * Задать маску отсечения.
     */
    clip(): void;

    /**
     * Подготовить сцену для рендеринга.
     * @param view Матрица вида.
     * @param projection Матрица проекции.
     * @param background Фон экрана.
     * @param width Ширина кадрового буфера.
     * @param height Высота кадрового буфера.
     * @param printing Признак печати.
     */
    beginRender(
        view: mat4,
        projection: mat4,
        background: vec4,
        width: number,
        height: number,
        printing: boolean
    ): void;

    /**
     * Применить матрицу преобразования.
     */
    pushMatrix(): void;

    /**
     * Отменить применение последней матрицы.
     */
    popMatrix(): void;

    /**
     * Умножить текущую матрицу на другую.
     * @param m Матрица умножения.
     */
    multMatrix(m: mat4): void;

    /**
     * Нарисовать линию в пространстве.
     * @param a Первая точка линии.
     * @param b Вторая точка линии.
     */
    line3d(a: vec3, b: vec3): void;

    /**
     * Нарисовать текст в 3D-пространстве.
     * @param position Положение текста.
     * @param angle Угол поворота текста.
     * @param content Текстовая строка.
     * @param style Стиль шрифта.
     * @param alignment Выравнивание текста.
     */
    text3d(
        position: vec3,
        angle: number,
        content: string,
        style: TextStyle,
        alignment: TextAlignment
    ): void;

    /**
     * Нарисовать треугольник.
     * @param a Первая вершина.
     * @param b Вторая вершина.
     * @param c Третья вершина.
     */
    triangle3d(a: vec3, b: vec3, c: vec3): void;

    /**
     * Нарисовать сетку полигонов.
     * @param geometry Геометрическая сетка.
     */
    mesh(geometry: UuidGeometry3d): void;

    /**
     * Текущая мировая матрица.
     */
    readonly world: mat4;

    /**
     * Расторизатор.
     */
    readonly rasterizer: Rasterizer;

    /**
     * Цвет фона.
     */
    readonly background: vec4;

    /**
     * Ширина экрана.
     */
    readonly width: number;

    /**
     * Высота экрана.
     */
    readonly height: number;

    /**
     * Признак белого фона.
     */
    readonly isWhite: boolean;

    /**
     * Признак печатающего устройства.
     */
    readonly isPrinting: boolean;

    /**
     * Допустимая погрешность.
     */
    tolerance: number;

    /**
     * Цвет кисти.
     */
    color: rgba8unorm;

    /**
     * Линотип.
     */
    linetype: Linetype[] | undefined;

    /**
     * Масштаб штриховки.
     */
    ltscale: number;
}

/**
 * Интерфейс обработчика динамического рисования.
 */
declare interface DynamicHandler {
    /**
     * Метод для рисования в динамическом режиме.
     */
    readonly paint: DynamicCallback;

    /**
     * Привязки для динамического рисования (опционально).
     */
    readonly snaps?: OsnapObject;
}

/**
 * Тип обратного вызова для динамического рисования.
 */
declare type DynamicCallback = (
    dc: DeviceContext, // Контекст устройства
    camera: Camera,    // Камера
    cursorPosition: vec3 // Текущая позиция курсора
) => void;

/**
 * Тип для динамического рисования (может быть либо callback, либо полноценный обработчик).
 */
declare type DynamicPaint = DynamicCallback | DynamicHandler;

/**
 * Тип обратного вызова для запроса фрейма анимации.
 */
declare type AnimateRequestCallback = (k: number) => boolean | void;

/**
 * Тип альтернативных команд (ассоциативный массив команд).
 */
declare type AlternativeCommands = Record<string, string>;

/**
 * Тип предиката объекта (функция проверки условий объекта).
 */
declare type ObjectPredicate = (obj: CadViewObject) => boolean;

// Annotations

/**
 * Интерфейс метки аннотации.
 */
declare interface AnnotationLabel {
    /**
     * Основной текст аннотации (необязательно).
     */
    readonly text?: string;

    /**
     * Описание аннотации (необязательно).
     */
    readonly description?: string;

    /**
     * Заголовок аннотации (необязательно).
     */
    readonly label?: string;

    /**
     * Цвет заднего плана метки (необязательно).
     */
    readonly labelBackground?: string;

    /**
     * Цвет текста метки (необязательно).
     */
    readonly labelColor?: string;

    /**
     * Пиктограмма метки (необязательно).
     */
    readonly labelIcon?: string;

    /**
     * Картинка метки (необязательно).
     */
    readonly labelImage?: string;

    /**
     * Суффикс аннотации (необязательно).
     */
    readonly suffix?: string;
}

/**
 * Интерфейс указателя аннотации.
 */
declare interface AnnotationPointer {
    /**
     * Уникальный идентификатор указателя (необязательно).
     */
    readonly id?: string;

    /**
     * Позиция указателя.
     */
    readonly position: vec3;
}

/**
 * Интерфейс линейной фигуры аннотации.
 */
declare interface AnnotationShapeLine {
    /**
     * Тип фигуры ('line').
     */
    type: 'line';

    /**
     * Цвет линии (необязательно).
     */
    readonly color?: string;

    /**
     * Толщина линии (необязательно).
     */
    readonly width?: number;

    /**
     * Первая точка линии.
     */
    readonly a: vec3;

    /**
     * Вторая точка линии.
     */
    readonly b: vec3;
}

/**
 * Интерфейс полилинии аннотации.
 */
declare interface AnnotationShapePolyline {
    /**
     * Тип фигуры ('polyline').
     */
    type: 'polyline';

    /**
     * Цвет линии (необязательно).
     */
    readonly color?: string;

    /**
     * Цвет заливки (необязательно).
     */
    readonly fillColor?: string;

    /**
     * Толщина линии (необязательно).
     */
    readonly width?: number;

    /**
     * Массив точек полилинии.
     */
    readonly points: readonly vec3[];
}

/**
 * Объединённый тип фигур аннотации.
 */
declare type AnnotationShape = AnnotationShapeLine | AnnotationShapePolyline;

/**
 * Тип динамического рисования аннотации.
 */
declare type AnnotationDynamicPaint = (
    annotation: Annotation | any, // Сама аннотация
    dc: DeviceContext, // Контекст устройства
    camera: Camera, // Камера
    active: boolean // Признак активности аннотации
) => void;

/**
 * Интерфейс базовой аннотации.
 */
declare interface AnnotationBase {
    /** Уникальный идентификатор аннотации. */
    readonly id: string;

    /** Описание аннотации (необязательно). */
    readonly description?: string;

    /** Команда активации (необязательно). */
    readonly activateCommand?: string | ((annotation: AnnotationBase) => void);

    /** Команда двойного клика (необязательно). */
    readonly dblCommand?: string | ((annotation: AnnotationBase) => void);

    /** Контекст (необязательно). */
    readonly context?: string;

    /** Признак объединения аннотаций (необязательно). */
    readonly merge?: boolean;

    /**
     * Метод динамического рисования (необязательно).
     * @param annotation Текущая аннотация.
     * @param dc Контекст устройства.
     * @param camera Камера.
     * @param active Признак активности.
     */
    readonly dynamicPaint?: AnnotationDynamicPaint;

    /**
     * Объект объектной зацепки (необязательно).
     */
    readonly snaps?: OsnapObject;
}

/**
 * Интерфейс указателей аннотаций.
 */
declare interface AnnotationPointers {
    /** Массив указателей (необязательно). */
    readonly pointers?: readonly AnnotationPointer[];

    /**
     * Команда на нажатие указателя (необязательно).
     * @param annotation Текущая аннотация.
     * @param pointer Нажатый указатель.
     */
    readonly pointerCommand?: string | ((annotation: AnnotationBase, pointer: AnnotationPointer) => void);
}

/**
 * Интерфейс простой аннотации.
 */
declare interface AnnotationSimple extends AnnotationBase, AnnotationLabel, AnnotationPointers {
    /** Тип аннотации. */
    readonly type: 'simple';

    /** Позиция аннотации. */
    readonly position: vec3;

    /** Массив надписей (необязательно). */
    readonly labels?: readonly AnnotationLabel[];

    /** Массив фигур аннотации (необязательно). */
    readonly shapes?: readonly AnnotationShape[];

    /** Массив активных фигур аннотации (необязательно). */
    readonly activeShapes?: readonly AnnotationShape[];

    /** Расположение аннотации относительно объекта. */
    readonly attachment?: 'center' | 'below' | 'above';
}

/**
 * Интерфейс аннотации-изображения.
 */
declare interface AnnotationIconed extends AnnotationBase, IconedObject {
    /** Тип аннотации. */
    readonly type: 'image';

    /** Позиция аннотации. */
    readonly position: vec3;

    /** Размер изображения (необязательно). */
    readonly size?: number;
}

/**
 * Интерфейс аннотации с фигурами.
 */
declare interface AnnotationShaped extends AnnotationBase {
    /** Тип аннотации. */
    readonly type: 'shaped';

    /** Массив фигур аннотации. */
    readonly shapes: readonly AnnotationShape[];

    /** Массив активных фигур аннотации (необязательно). */
    readonly activeShapes?: readonly AnnotationShape[];
}

/**
 * Интерфейс композитной аннотации.
 */
declare interface AnnotationCompound extends AnnotationBase {
    /** Тип аннотации. */
    readonly type: 'compound';

    /** Массив вложенных аннотаций. */
    readonly annotations: readonly Annotation[];
}

/**
 * Интерфейс аннотации-раздела.
 */
declare interface AnnotationSection extends AnnotationBase, AnnotationPointers {
    /** Тип аннотации. */
    readonly type: 'section';

    /** Метка раздела. */
    readonly label: string;

    /** Массив позиций (точек раздела). */
    readonly position: vec3[];

    /** Нормаль (необязательно). */
    readonly normal?: vec3;

    /** Цвет (необязательно). */
    readonly color?: string;

    /** Цвет текста (необязательно). */
    readonly textColor?: string;
}

/**
 * Тип аннотации.
 */
declare type Annotation = AnnotationSimple | AnnotationIconed | AnnotationShaped | AnnotationCompound | AnnotationSection;

/**
 * Интерфейс инициализации аннотации.
 */
declare type AnnotationInit<T extends Annotation> = Omit<T, 'id'> & { id?: string; };

/**
 * Интерфейс слоя аннотаций.
 */
declare interface AnnotationLayer {
    /** Уникальный идентификатор слоя. */
    readonly id: string;

    /** Приоритет слоя. */
    readonly priority: number;

    /** Признак пустоты слоя. */
    readonly empty: boolean;

    /** Признак видимости слоя. */
    visible: boolean;

    /**
     * Добавить аннотацию.
     * @param annotation Инициализатор аннотации.
     */
    add<T extends Annotation>(annotation: AnnotationInit<T>): T;

    /**
     * Получить аннотацию по её идентификатору.
     * @param id Идентификатор аннотации.
     */
    get(id: string): Annotation | undefined;

    /**
     * Удалить аннотацию.
     * @param id Идентификатор аннотации.
     */
    remove(id: string): boolean;

    /**
     * Посетить аннотации.
     * @param frustum Видимая зона (опционально).
     * @param visitor Колбек посетителя.
     */
    walk(frustum: ViewFrustum | undefined, visitor: (annotation: Annotation, bounds: box3) => void): void;

    /**
     * Очистить слой.
     */
    clear(): void;

    /**
     * Событие сокрытия слоя.
     */
    onDidHide: EventHandler<void>;

    /**
     * Событие появления слоя.
     */
    onDidShow: EventHandler<void>;
}

/**
 * Интерфейс уровней аннотаций.
 */
declare interface AnnotationLayers {
    /**
     * Получить слой аннотаций.
     * @param id Идентификатор слоя.
     */
    get(id: string): AnnotationLayer | undefined;

    /**
     * Создать новый слой аннотаций.
     * @param id Идентификатор слоя (опционально).
     * @param priority Приоритет слоя (опционально).
     */
    create(id?: string, priority?: number): AnnotationLayer;

    /**
     * Освободить ресурсы слоя.
     * @param layer Освобождаемый слой.
     */
    release(layer: AnnotationLayer): void;

    /**
     * Посетить все слои аннотаций.
     * @param visitor Колбек посетителя.
     */
    walk(visitor: (layer: AnnotationLayer) => void): void;

    /** Стандартный слой аннотаций. */
    readonly standard: AnnotationLayer;

    /** Признак пустоты уровней аннотаций. */
    readonly empty: boolean;

    /** Признак видимости всех слоев. */
    visible: boolean;
}

/**
 * Тип двумерного вектора.
 */
declare type vec2 = [number, number];

/**
 * Тип трёхмерного вектора.
 */
declare type vec3 = [number, number, number];

/**
 * Тип четырёхмерного вектора.
 */
declare type vec4 = [number, number, number, number];

/**
 * Тип двухмерного ограничивающего прямоугольника.
 */
declare type box2 = [number, number, number, number];

/**
 * Тип трёхмерного ограничивающего прямоугольника.
 */
declare type box3 = [number, number, number, number, number, number] | Float32Array | Float64Array;

/**
 * Тип сферы.
 */
declare type sphere3 = [number, number, number, number];

/**
 * Тип матриц 4×4.
 */
declare type mat4 = [number, number, number, number, number, number, number, number, number, number, number, number, number, number, number, number] | Float32Array | Float64Array;

/**
 * Тип луча в трёхмерном пространстве.
 */
declare type ray3 = [number, number, number, number, number, number];

/**
 * Тип двумерной линии.
 */
declare type line2 = [number, number, number];

/**
 * Интерфейс арки.
 */
declare interface arc {
    /** Центр арки. */
    center: vec2;

    /** Радиус арки. */
    radius: number;

    /** Угол начала арки. */
    angle: number;

    /** Угловой размер арки. */
    span: number;
}

/**
 * Интерфейс круга в трёхмерном пространстве.
 */
declare interface circle3 {
    /** Нормаль к кругу. */
    normal: vec3;

    /** Центр круга. */
    center: vec3;

    /** Радиус круга. */
    radius: number;
}

/**
 * Интерфейс арки в трёхмерном пространстве.
 */
declare interface arc3 {
    /** Нормаль к арке. */
    normal: vec3;

    /** Центр арки. */
    center: vec3;

    /** Радиус арки. */
    radius: number;

    /** Угол начала арки. */
    angle: number;

    /** Угловой размер арки. */
    span: number;
}

/**
 * Интерфейс плоскости.
 */
declare type plane3 = [number, number, number, number];

/**
 * Интерфейс видимой зоны (видовая пирамида).
 */
declare interface ViewFrustum {
    /**
     * Получить луч.
     * @param target Результирующий луч.
     */
    ray(target: ray3): void;

    /**
     * Получить ограничивающий параллелепипед.
     * @param target Результирующий параллелепипед.
     */
    box(target: box3): void;

    /**
     * Определить допуск для объекта в зоне.
     * @param obj Объект.
     * @param viewport Экранные координаты.
     */
    tolerance(obj: sphere3, viewport: vec2): number;

    /**
     * Проверить попадание точки внутрь зоны.
     * @param point Точка.
     */
    containsPoint(point: vec3): boolean;

    /**
     * Проверить пересечение с параллелепипедом.
     * @param box Параллелепипед.
     */
    intersectBox(box: box3): boolean;

    /**
     * Проверить пересечение с сегментом.
     * @param a Первая точка сегмента.
     * @param b Вторая точка сегмента.
     */
    intersectSegment(a: vec3, b: vec3): boolean;

    /**
     * Преобразовать видовую пирамиду.
     * @param matrix Матрица преобразования.
     */
    transformed(matrix: mat4): ViewFrustum;

    /**
     * Проверить обрезку линии.
     * @param targetA Первая точка результирующей линии.
     * @param targetB Вторая точка результирующей линии.
     * @param line Линейный объект.
     */
    clipLine(targetA: vec3, targetB: vec3, line: ray3): boolean;

    /**
     * Проверить обрезку луча.
     * @param targetA Первая точка результирующего луча.
     * @param targetB Вторая точка результирующего луча.
     * @param ray Луч.
     */
    clipRay(targetA: vec3, targetB: vec3, ray: ray3): boolean;

    /**
     * Проверить обрезку сегмента.
     * @param targetA Первая точка результирующего сегмента.
     * @param targetB Вторая точка результирующего сегмента.
     * @param a Первая точка сегмента.
     * @param b Вторая точка сегмента.
     */
    clipSegment(targetA: vec3, targetB: vec3, a: vec3, b: vec3): boolean;
}

