/**
 * Интерфейс пользовательского представления.
 */
declare interface DefinedView extends View { }

/**
 * Коллекция всех зарегистрированных каналов
 */
declare interface OutputChannels {
    /**
     * Главный канал.
     *
     * Может использоваться для вывода общих сообщений, когда создание нового канала нецелесообразно
     */
    readonly main: OutputChannel;

    /**
     * Текущий активный канал, отображаемый в пользовательском интерфейсе
     */
    readonly active: OutputChannel | undefined;

    /**
     * Список всех зарегистрированных каналов
     */
    readonly channels: readonly OutputChannel[];
}

/**
 * Интерфейс записи в журнале вывода
 */
declare interface OutputRecord {
    /**
     * Время наступления события
     */
    time: number;

    /**
     * Текстовое значение с поддержкой управляющих последовательностей ANSI
     */
    value: string;

    /**
     * Опциональное значение уровня логирования
     */
    level?: LogLevel;

    /**
     * Количество подряд наступивших одинаковых событий
     */
    count?: number;
}

/**
 * Выходной канал — это контейнер для текстовой информации, доступной только для чтения.
 *
 * Чтобы получить экземпляр `OutputChannel`, используйте createOutputChannel
 */
declare interface OutputChannel {

    /**
     * Удобочитаемое имя этого выходного канала.
     */
    readonly name: string;

    /**
     * Текущий уровень журнала канала.
     */
    readonly logLevel: LogLevel;

    /**
     * Событие, которое вызывается при смене уровня логирования
     */
    readonly onDidChangeLogLevel: EventHandler<LogLevel>;

    /**
     * Значения всех записей в журнале
     */
    readonly values: OutputRecord[];

    /**
     * Добавить указанное значение к каналу.
     *
     * @param value Текстовое значение с поддержкой управляющих последовательностей ANSI
     */
    append(value: string): void;

    /**
     * Добавьте указанное значение и символ перевода строки к каналу.
     *
     * @param value Текстовое значение с поддержкой управляющих последовательностей ANSI
     */
    appendLine(value: string): void;

    /**
     * Заменяет весь вывод канала заданным значением
     *
     * @param value Текстовое значение с поддержкой управляющих последовательностей ANSI
     */
    replace(value: string): void;

    /**
     * Удаляет весь вывод канала
     */
    clear(): void;

    /**
     * Фокусирует вывод в пользовательском интерфейсе
     *
     * @param preserveFocus Когда `true` нижняя панель не будет принудительно показана.
     */
    show(preserveFocus?: boolean): void;

    /**
     * Удаляет и освобождает выделенные ресурсы
     */
    dispose(): void;


    /**
     * Засекает время на выполнение операции с заданной меткой
     * @param message Выводимое сообщение с поддержкой управляющих последовательностей ANSI
     * @param level Уровень логирования
     * @param args Позиционные аргументы, заменяющие соответствующие метки в @argument message
     */
    time(message: string, level: LogLevel, ...args: any[]): void;


    /**
     * Выводит сообщение со временем операции с заданной меткой
     * @param message Выводимое сообщение с поддержкой управляющих последовательностей ANSI
     * @param args Позиционные аргументы, заменяющие соответствующие метки в @argument message
     */
    timeEnd(message: string, ...args: any[]): void;

    /**
     * Выводит заданное сообщение трассировки в канал. Используйте этот метод для регистрации подробной информации.
     *
     * Сообщение регистрируется только в том случае, если канал настроен на отображение уровня журнала {@link LogLevel.Trace trace}.
     *
     * @param message Выводимое сообщение с поддержкой управляющих последовательностей ANSI
     * @param args Позиционные аргументы, заменяющие соответствующие метки в @argument message
     */
    trace(message: string, ...args: any[]): void;

    /**
     * Выводит указанное отладочное сообщение на канал.
     *
     * Сообщение регистрируется только в том случае, если канал настроен на отображение уровня журнала {@link LogLevel.Debug debug}.
     *
     * @param message Выводимое сообщение с поддержкой управляющих последовательностей ANSI
     * @param args Позиционные аргументы, заменяющие соответствующие метки в @argument message
     */
    debug(message: string, ...args: any[]): void;

    /**
     * Выводит указанное информационное сообщение на канал.
     *
     * Сообщение регистрируется только в том случае, если канал настроен на отображение уровня журнала {@link LogLevel.Info info}.
     *
     * @param message Выводимое сообщение с поддержкой управляющих последовательностей ANSI
     * @param args Позиционные аргументы, заменяющие соответствующие метки в @argument message
     */
    info(message: string, ...args: any[]): void;

    /**
     * Выводит указанное предупредительное сообщение на канал.
     *
     * Сообщение регистрируется только в том случае, если канал настроен на отображение уровня журнала {@link LogLevel.Warning warning}.
     *
     * @param message Выводимое сообщение с поддержкой управляющих последовательностей ANSI
     * @param args Позиционные аргументы, заменяющие соответствующие метки в @argument message
     */
    warn(message: string, ...args: any[]): void;

    /**
     * Выводит указанное сообщение об ошибке в канал.
     *
     * Сообщение регистрируется только в том случае, если канал настроен на отображение уровня журнала {@link LogLevel.Error error}.
     * Канал автоматически отображается в пользовательском интерфейсе.
     *
     * @param message Выводимое сообщение с поддержкой управляющих последовательностей ANSI
     * @param args Позиционные аргументы, заменяющие соответствующие метки в @argument message
     */
    error(error: string | Error, ...args: any[]): void;
}

/**
* Тип функции активации диагностики.
* @param diagnostic Диагностика, которую нужно активировать.
* @param active Флаг повторной активации сообщения
*/
declare type DiagnosticActivation = ((diagnostic: Diagnostic, active: boolean) => void) | string;

/**
* Представляет диагностику, такую как ошибка или предупреждение о коллизии. Объекты диагностики
* действительны только в области проекта.
*/
declare interface Diagnostic {

    /**
     * Активация данной диагностики.
     */
    activation?: DiagnosticActivation;

    /**
     * Человеко-читаемое сообщение.
     */
    message: string;

    /**
     * Степень серьезности.
     */
    severity: DiagnosticSeverity;

    /**
     * Человеко-читаемая строка, описывающая источник этой
     * диагностики, например 'Коллизия геометрии'.
     */
    source?: string;

    /**
     * Дополнительные метаданные о диагностике.
     */
    tags?: DiagnosticTag;

    /**
     * Подсказка
     */
    tooltip?: string;
}

/**
* Коллекция диагностики - это контейнер, который управляет набором
* {@link Diagnostic диагностики}. Диагностика всегда относится к
* коллекции диагностики и ресурсу.
*
* Чтобы получить экземпляр `DiagnosticCollection` используйте
* {@link Context.createDiagnosticCollection}.
*/
declare interface DiagnosticCollection {

    /**
     * Имя этой коллекции диагностики, например `Коллизия геометрии`. Каждая диагностика
     * из этой коллекции будет связана с этим именем.
     */
    readonly name: string;

    /**
     * Только для чтения ссылка на расширение.
     */
    readonly extension: Extension;

    /**
     * Назначить диагностику для данного ресурса. Заменит
     * существующую диагностику для этого ресурса.
     *
     * @param uri Идентификатор ресурса.
     * @param diagnostics Массив диагностики или `undefined`
     */
    set(uri: string, diagnostics: readonly Diagnostic[] | undefined): void;

    /**
     * Заменить диагностику для нескольких ресурсов в этой коллекции.
     *
     * @param entries Массив кортежей, например `[[file1, [d1, d2]], [file2, [d3, d4, d5]]]`, или `undefined`.
     */
    set(entries: ReadonlyArray<[string, readonly Diagnostic[] | undefined]>): void;

    /**
     * Удалить все диагностики из этой коллекции, которые принадлежат
     * предоставленному `uri`. То же, что и `#set(uri, undefined)`.
     *
     * @param uri Идентификатор ресурса.
     */
    delete(uri: string): void;

    /**
     * Удалить все диагностики из этой коллекции.
     */
    clear(): void;

    /**
     * Перебрать каждую запись в этой коллекции.
     *
     * @param callback Функция для выполнения для каждой записи.
     */
    forEach(callback: (uri: string, diagnostics: readonly Diagnostic[]) => void): void;

    /**
     * Получить диагностику для данного ресурса. *Note* что вы не можете
     * изменить массив диагностики, возвращаемый из этого вызова.
     *
     * @param uri Идентификатор ресурса.
     * @returns Неизменяемый массив {@link Diagnostic диагностики} или `undefined`.
     */
    get(uri: string): readonly Diagnostic[] | undefined;

    /**
     * Проверить, содержит ли эта коллекция диагностику для
     * данного ресурса.
     *
     * @param uri Идентификатор ресурса.
     * @returns `true` если эта коллекция имеет диагностику для данного ресурса.
     */
    has(uri: string): boolean;

    /**
     * Удалить и освободить связанные ресурсы..
     */
    dispose(): void;
}

/** Диагностическое правило. Позволяет выполнять диагностические проверки проекта */
declare interface DiagnosticRule<T extends any> {

    /**
    * Создание диагностического правила
    * @return Возвращает любой объект сериализуемый в JSON.
    */
    createRule(): Promise<T>;

    /** Выполнение диагностической проверки */
    execute(app: Application, rule: readonly T, diagnostics: DiagnosticCollection, progress: WorkerProgress): Promise<void>;
}